/* eslint-disable */
import React, { useState, useEffect, useCallback } from 'react';
import api from '../utils/api';
import { useAuth } from '../contexts/AuthContext';
import Sidebar from '../components/Sidebar';
import Topbar from '../components/Topbar';

const NAVY = '#0B1120';
const ORANGE = '#FF6B35';
const BG = '#f0f4ff';
const RK_LOGO = "data:image/png;base64,";
const HP_LOGO = "data:image/png;base64,";

const CAT_META = {
  'Inquiries':          { color: '#6366f1', bg: '#eef2ff', grad: 'linear-gradient(135deg,#6366f1,#4f46e5)' },
  'Billing Complaints': { color: '#ef4444', bg: '#fef2f2', grad: 'linear-gradient(135deg,#ef4444,#dc2626)' },
  'General Complaints': { color: '#8b5cf6', bg: '#f5f3ff', grad: 'linear-gradient(135deg,#8b5cf6,#7c3aed)' },
  'Service Requests':   { color: '#10b981', bg: '#ecfdf5', grad: 'linear-gradient(135deg,#10b981,#059669)' },
  'Feedback & Others':  { color: '#f59e0b', bg: '#fffbeb', grad: 'linear-gradient(135deg,#f59e0b,#d97706)' },
  'New Updates':        { color: '#f97316', bg: '#fff7ed', grad: 'linear-gradient(135deg,#f97316,#ea580c)' },
};

const PANEL_FILTER = {
  'inquiries':   f => f.category === 'Inquiries',
  'inq-runaki':  f => f.category === 'Inquiries' && (f.subcategory||'').toLowerCase().includes('runaki'),
  'inq-kyc':     f => f.category === 'Inquiries' && (f.subcategory||'').toLowerCase().includes('kyc'),
  'inq-billing': f => f.category === 'Inquiries' && (f.subcategory||'').toLowerCase().includes('billing'),
  'inq-dunning': f => f.category === 'Inquiries' && (f.subcategory||'').toLowerCase().includes('dunning'),
  'inq-epsule':  f => f.category === 'Inquiries' && (f.subcategory||'').toLowerCase().includes('psule'),
  'inq-ussd':    f => f.category === 'Inquiries' && (f.subcategory||'').toLowerCase().includes('ussd'),
  'inq-solar':   f => f.category === 'Inquiries' && (f.subcategory||'').toLowerCase().includes('solar'),
  'billing':     f => f.category === 'Billing Complaints',
  'general':     f => f.category === 'General Complaints',
  'service':     f => f.category === 'Service Requests',
  'feedback':    f => f.category === 'Feedback & Others',
  '_updates':    f => f.category === 'New Updates',
};

const PANEL_LABELS = {
  'inquiries':'Inquiries','inq-runaki':'Runaki Project','inq-kyc':'KYC',
  'inq-billing':'Billing Inquiries','inq-dunning':'Dunning','inq-epsule':'e-Psûle',
  'inq-ussd':'USSD','inq-solar':'Solar & Other','billing':'Billing Complaints',
  'general':'General Complaints','service':'Service Requests',
  'feedback':'Feedback & Others','_updates':'New Updates',
  '_restree':'Resolution Tree','_scripts':'Scripts & Processes','_priority':'Case Priorities',
  '_search':'Search Results',
};

export default function AgentView() {
  const { user } = useAuth();
  const [faqs, setFaqs]       = useState([]);
  const [tip, setTip]         = useState(null);
  const [loading, setLoading] = useState(true);
  const [panel, setPanel]     = useState('billing');
  const [lang, setLang]       = useState('en');
  const [search, setSearch]   = useState('');
  const [open, setOpen]       = useState({});

  const load = useCallback(async () => {
    try {
      const fr = await api.get('/faqs');
      setFaqs(fr.data);
    } catch (err) {
      console.error('FAQs load error:', err);
    } finally { setLoading(false); }
    try {
      const tr = await api.get('/tips/latest');
      if (tr.data) setTip(tr.data);
    } catch (err) {
      console.error('Tip load error:', err);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  const tog = id => setOpen(p => ({ ...p, [id]: !p[id] }));

  const panelFaqs = () => {
    if (search) return faqs.filter(f =>
      [f.question_en, f.answer_en, f.category, f.subcategory].some(x =>
        (x||'').toLowerCase().includes(search.toLowerCase())
      )
    );
    const fn = PANEL_FILTER[panel];
    return fn ? faqs.filter(fn) : [];
  };

  const grouped = items => {
    const g = {};
    items.forEach(f => {
      const k = f.subcategory || 'General';
      if (!g[k]) g[k] = [];
      g[k].push(f);
    });
    return g;
  };

  const items = panelFaqs();
  const groups = grouped(items);
  const isSpecial = ['_restree','_scripts','_priority'].includes(panel);

  if (loading) return (
    <div style={{ display:'flex', height:'100vh', background:BG, fontFamily:"'Inter',sans-serif", alignItems:'center', justifyContent:'center' }}>
      <div style={{ textAlign:'center' }}>
        <div style={{ fontSize:'48px', marginBottom:'16px' }}>⚡</div>
        <div style={{ fontSize:'16px', color:'#64748b', fontWeight:'700' }}>Loading Knowledge Base...</div>
      </div>
    </div>
  );

  return (
    <div style={S.layout}>
      <Sidebar panel={panel} setPanel={setPanel} search={search} setSearch={setSearch} />
      <div style={S.body}>
        <Topbar
          title={PANEL_LABELS[search ? '_search' : panel] || 'Knowledge Base'}
          subtitle={search ? `${items.length} results for "${search}"` : `${items.length} topics`}
          rkLogo={RK_LOGO} hpLogo={HP_LOGO}
        />
        <div style={S.content}>

          {/* Daily Tip Banner */}
          {tip && !isSpecial && !search && (
            <div style={S.tipBanner}>
              <div style={S.tipGlow} />
              <div style={S.tipIconWrap}><span style={{ fontSize:'24px' }}>💡</span></div>
              <div style={S.tipText}>
                <div style={S.tipLabel}>Daily Tip · {tip.category}</div>
                <div style={S.tipTitle}>{tip.title}</div>
                <div style={S.tipContent}>{tip.content}</div>
              </div>
              <div style={S.tipMeta}>by {tip.author} · {new Date(tip.created_at).toLocaleDateString()}</div>
            </div>
          )}

          {/* Lang toggle */}
          {!isSpecial && (
            <div style={S.langBar}>
              <span style={S.langBarLabel}>🌐 Language</span>
              {[['en','🇬🇧 English'],['ku','🇮🇶 کوردی'],['both','Both']].map(([l,lbl]) => (
                <button key={l} onClick={() => setLang(l)}
                  style={{ ...S.langBtn, ...(lang===l ? S.langBtnOn : {}) }}>
                  {lbl}
                </button>
              ))}
              {search && (
                <button style={S.clearBtn} onClick={() => { setSearch(''); setPanel('billing'); }}>
                  ✕ Clear
                </button>
              )}
            </div>
          )}

          {/* Special panels */}
          {panel === '_restree'  && <ResolutionTree />}
          {panel === '_scripts'  && <Scripts />}
          {panel === '_priority' && <Priority />}

          {/* FAQ content */}
          {!isSpecial && (
            items.length === 0 ? (
              <div style={S.empty}>
                <div style={{ fontSize:'52px', marginBottom:'14px' }}>{search ? '🔍' : '📭'}</div>
                <div style={S.emptyTitle}>{search ? `No results for "${search}"` : 'No content here yet'}</div>
                <div style={S.emptySub}>{search ? 'Try different keywords' : 'Content will be added soon'}</div>
              </div>
            ) : (
              Object.entries(groups).map(([sub, subItems]) => {
                const meta = CAT_META[subItems[0]?.category] || { color: NAVY, bg: '#f1f5f9' };
                return (
                  <div key={sub} style={S.subBlock}>
                    <div style={S.subHeader}>
                      <div style={{ ...S.subDot, background: meta.grad }} />
                      <span style={{ ...S.subTitle, color: meta.color }}>{sub}</span>
                      <span style={{ ...S.subCount, background: meta.bg, color: meta.color }}>{subItems.length}</span>
                    </div>
                    <div style={S.cardGrid}>
                      {subItems.map(f => (
                        <FAQCard key={f.id} faq={f} lang={lang} isOpen={open[f.id]} onToggle={() => tog(f.id)} />
                      ))}
                    </div>
                  </div>
                );
              })
            )
          )}
        </div>
      </div>
    </div>
  );
}

function FAQCard({ faq, lang, isOpen, onToggle }) {
  const meta = CAT_META[faq.category] || { color: NAVY, bg: '#f1f5f9', grad: 'linear-gradient(135deg,#0B1120,#1e293b)' };
  return (
    <div style={{ ...S.card, ...(isOpen ? S.cardOpen : {}) }}>
      <button style={S.cardHead} onClick={onToggle}>
        <div style={{ width:'4px', alignSelf:'stretch', borderRadius:'4px', background: meta.grad, flexShrink:0 }} />
        <div style={{ flex:1, textAlign:'left' }}>
          <div style={S.cardQ}>{faq.question_en}</div>
          {(lang === 'ku' || lang === 'both') && faq.question_ku && (
            <div style={S.cardQku}>{faq.question_ku}</div>
          )}
        </div>
        <div style={{ ...S.cardChev, transform: isOpen ? 'rotate(180deg)' : 'none', color: isOpen ? meta.color : '#94a3b8' }}>▼</div>
      </button>
      {isOpen && (
        <div style={S.cardBody}>
          <div style={{ height:'1px', background:`${meta.color}18`, marginBottom:'14px' }} />
          {(lang === 'en' || lang === 'both') && (
            <div style={S.cardAns}>{faq.answer_en}</div>
          )}
          {(lang === 'ku' || lang === 'both') && (
            faq.answer_ku
              ? <div style={{ ...S.cardKurd, borderLeftColor: meta.color, marginTop: lang === 'both' ? '14px' : '0' }}>
                  <div style={{ ...S.cardKurdLabel, color: meta.color }}>🇮🇶 Kurdish — کوردی</div>
                  <div style={{ ...S.cardAns, direction:'rtl', textAlign:'right' }}>{faq.answer_ku}</div>
                </div>
              : <div style={S.noKu}>Kurdish translation coming soon</div>
          )}
          <div style={S.cardFoot}>
            <span style={{ ...S.catTag, background: meta.bg, color: meta.color }}>{faq.category}</span>
            {faq.subcategory && <span style={S.subTag}>{faq.subcategory}</span>}
          </div>
        </div>
      )}
    </div>
  );
}

function ResolutionTree() {
  const cols = [
    { n:1, t:'Inquiries', g:'linear-gradient(135deg,#6366f1,#4f46e5)', items:['KYC','Runaki Project','→Rollout','→Smart Meters','→Private Generators','Billing Inquiries','→Tariff','→Discounts','→Bill Amount','→Consumption','→Payment Location','Dunning','→Process','→Amount/Date','E-psûle','USSD'] },
    { n:2, t:'Billing Complaints', g:'linear-gradient(135deg,#ef4444,#dc2626)', items:['High Bill/High Debt','Bill Not Received','Wrong Tariff','Zero Bill','Other Billing'] },
    { n:3, t:'General Complaints', g:'linear-gradient(135deg,#8b5cf6,#7c3aed)', items:['Outage','→Planned','→Unplanned','→Non-Payment','→SM Issue','Message Not Received','→Not KYCed','→No Readings','USSD Code','Fraud','Block Comms','Private Generators'] },
    { n:4, t:'Service Requests', g:'linear-gradient(135deg,#10b981,#059669)', items:['Smart Meter','→Linking','→Installation','Data Amendment','Move In','Move Out','Temp Disconnection','Debt Clearance','Instalment Contract','Change Holder','TR Access'], note:'⚠️ Redirected to CO' },
    { n:5, t:'Feedback & Others', g:'linear-gradient(135deg,#f59e0b,#d97706)', items:['Feedback','Others'] },
  ];
  return (
    <div>
      <div style={{ display:'flex', justifyContent:'center', marginBottom:'24px' }}>
        <div style={{ background:'linear-gradient(135deg,#0B1120,#1e293b)', color:'#fff', padding:'12px 36px', borderRadius:'16px', fontWeight:'800', fontSize:'15px', boxShadow:'0 8px 24px rgba(11,17,32,0.4)', display:'flex', alignItems:'center', gap:'10px' }}>
          📞 Call Center
        </div>
      </div>
      <div style={{ display:'flex', gap:'10px', overflowX:'auto', paddingBottom:'16px' }}>
        {cols.map(col => (
          <div key={col.n} style={{ flex:1, minWidth:'165px' }}>
            <div style={{ background:col.g, color:'#fff', padding:'10px 12px', borderRadius:'14px', fontWeight:'800', fontSize:'11.5px', marginBottom:'8px', display:'flex', alignItems:'center', gap:'8px', boxShadow:'0 4px 12px rgba(0,0,0,0.15)' }}>
              <span style={{ background:'rgba(255,255,255,0.2)', borderRadius:'50%', width:'22px', height:'22px', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'10px', fontWeight:'900', flexShrink:0 }}>{col.n}</span>
              {col.t}
            </div>
            <div style={{ display:'flex', flexDirection:'column', gap:'4px' }}>
              {col.items.map((item,i) => {
                const isSub = item.startsWith('→');
                return (
                  <div key={i} style={{ padding:isSub?'4px 8px 4px 18px':'7px 10px', borderRadius:'9px', fontSize:isSub?'10.5px':'11.5px', fontWeight:isSub?'500':'700', background:isSub?'#f8fafc':'#0B1120', color:isSub?'#475569':'#fff', border:`1px solid ${isSub?'#e2e8f0':'transparent'}` }}>
                    {isSub && <span style={{ opacity:0.3, marginRight:'4px' }}>└</span>}
                    {item.replace('→','')}
                  </div>
                );
              })}
              {col.note && <div style={{ fontSize:'11px', color:ORANGE, fontWeight:'700', padding:'6px 8px', background:'#fff7ed', borderRadius:'9px', marginTop:'4px', border:'1px solid #fed7aa' }}>{col.note}</div>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function Scripts() {
  const scripts = [
    { t:'👋 Greeting', s:'Good [morning/afternoon/evening], thank you for calling Runaki. My name is [name], how may I assist you today?' },
    { t:'📋 Get User Info', s:'May I please have your name and account/meter number to look up your account?' },
    { t:'⏸️ Requesting Hold', s:'I need to place you on a brief hold while I look into this. It should take no more than 2 minutes. Is that okay?' },
    { t:'⏰ Still on Hold', s:"Thank you for holding. I'm still looking into this for you, I appreciate your patience." },
    { t:'▶️ Returning from Hold', s:'Thank you for holding, [customer name]. I have the information you need.' },
    { t:'✅ Closing', s:'Is there anything else I can help you with today? Thank you for calling Runaki. Have a great day!' },
  ];
  return (
    <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(320px,1fr))', gap:'14px' }}>
      {scripts.map((s,i) => (
        <div key={i} style={{ background:'#fff', borderRadius:'16px', padding:'20px 22px', border:'1px solid #e2e8f0', boxShadow:'0 2px 8px rgba(0,0,0,0.04)', overflow:'hidden', position:'relative' }}>
          <div style={{ position:'absolute', top:0, left:0, right:0, height:'3px', background:`linear-gradient(90deg,${ORANGE},#ff9a6c)` }} />
          <div style={{ fontSize:'11px', fontWeight:'800', color:'#0B1120', marginBottom:'12px', textTransform:'uppercase', letterSpacing:'0.08em' }}>{s.t}</div>
          <div style={{ fontSize:'14px', color:'#475569', fontStyle:'italic', lineHeight:'1.75', borderLeft:`3px solid ${ORANGE}`, paddingLeft:'14px' }}>
            "{s.s}"
          </div>
        </div>
      ))}
    </div>
  );
}

function Priority() {
  const levels = [
    { level:'🟢 Low', color:'#16a34a', bg:'#f0fdf4', border:'#bbf7d0', items:['Billing errors','KYC issues','Cap issues','High bill/debt'] },
    { level:'🟡 Medium', color:'#d97706', bg:'#fffbeb', border:'#fde68a', items:['Ongoing non-critical complaints'] },
    { level:'🟠 High', color:'#ea580c', bg:'#fff7ed', border:'#fed7aa', items:['Unplanned outage','Paid >12h still disconnected','SM issue','Private generators','Disconnection leaflet'] },
    { level:'🔴 Urgent', color:'#dc2626', bg:'#fef2f2', border:'#fecaca', items:['Maintenance non-responsive','Maintenance visited but could not resolve'] },
  ];
  return (
    <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(260px,1fr))', gap:'14px' }}>
      {levels.map((lv,i) => (
        <div key={i} style={{ background:'#fff', borderRadius:'16px', overflow:'hidden', border:'1px solid #e2e8f0', boxShadow:'0 2px 8px rgba(0,0,0,0.04)' }}>
          <div style={{ background:lv.bg, padding:'16px 18px', borderBottom:`2px solid ${lv.border}` }}>
            <div style={{ fontSize:'16px', fontWeight:'800', color:lv.color }}>{lv.level}</div>
          </div>
          <div style={{ padding:'14px 18px' }}>
            {lv.items.map((item,j) => (
              <div key={j} style={{ display:'flex', gap:'10px', padding:'6px 0', borderBottom:j<lv.items.length-1?'1px solid #f1f5f9':'none' }}>
                <span style={{ color:lv.color, flexShrink:0, fontSize:'12px', marginTop:'2px' }}>●</span>
                <span style={{ fontSize:'13.5px', color:'#334155', lineHeight:'1.5' }}>{item}</span>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

const S = {
  layout: { display:'flex', height:'100vh', overflow:'hidden', background:BG, fontFamily:"'Inter','Segoe UI',sans-serif" },
  body: { flex:1, display:'flex', flexDirection:'column', overflow:'hidden', minWidth:0 },
  content: { flex:1, overflowY:'auto', padding:'24px 28px' },

  tipBanner: { background:'linear-gradient(135deg,#fff7ed,#fff3e8)', border:'1px solid #fed7aa', borderRadius:'18px', padding:'20px 24px', marginBottom:'22px', display:'flex', alignItems:'flex-start', gap:'18px', position:'relative', overflow:'hidden', boxShadow:'0 4px 20px rgba(255,107,53,0.12)' },
  tipGlow: { position:'absolute', top:'-40px', right:'-40px', width:'160px', height:'160px', background:'rgba(255,107,53,0.15)', borderRadius:'50%', filter:'blur(30px)', pointerEvents:'none' },
  tipIconWrap: { width:'48px', height:'48px', background:`linear-gradient(135deg,${ORANGE},#ff9a6c)`, borderRadius:'14px', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, boxShadow:'0 4px 14px rgba(255,107,53,0.35)' },
  tipText: { flex:1 },
  tipLabel: { fontSize:'10px', fontWeight:'800', color:ORANGE, textTransform:'uppercase', letterSpacing:'0.1em', marginBottom:'4px' },
  tipTitle: { fontSize:'16px', fontWeight:'800', color:'#9a3412', marginBottom:'6px', letterSpacing:'-0.01em' },
  tipContent: { fontSize:'13.5px', color:'#c2410c', lineHeight:'1.7' },
  tipMeta: { fontSize:'11px', color:'rgba(154,52,18,0.5)', fontWeight:'500', flexShrink:0, alignSelf:'flex-end' },

  langBar: { display:'flex', alignItems:'center', gap:'8px', marginBottom:'22px', flexWrap:'wrap' },
  langBarLabel: { fontSize:'12px', fontWeight:'700', color:'#94a3b8', marginRight:'4px' },
  langBtn: { padding:'7px 18px', borderRadius:'100px', border:'1.5px solid #e2e8f0', background:'#fff', fontSize:'12px', fontWeight:'700', cursor:'pointer', fontFamily:'inherit', color:'#64748b', transition:'all .15s', boxShadow:'0 1px 3px rgba(0,0,0,0.06)' },
  langBtnOn: { background:NAVY, color:'#fff', borderColor:NAVY, boxShadow:'0 4px 12px rgba(11,17,32,0.2)' },
  clearBtn: { marginLeft:'auto', background:'#fef2f2', border:'1px solid #fecaca', color:'#ef4444', borderRadius:'100px', padding:'6px 14px', fontSize:'12px', fontWeight:'700', cursor:'pointer', fontFamily:'inherit' },

  subBlock: { marginBottom:'28px' },
  subHeader: { display:'flex', alignItems:'center', gap:'10px', marginBottom:'14px' },
  subDot: { width:'10px', height:'10px', borderRadius:'50%', flexShrink:0 },
  subTitle: { fontSize:'11px', fontWeight:'800', textTransform:'uppercase', letterSpacing:'0.1em', flex:1 },
  subCount: { fontSize:'10px', fontWeight:'800', padding:'3px 10px', borderRadius:'100px' },
  cardGrid: { display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(340px,1fr))', gap:'12px' },

  card: { background:'#fff', borderRadius:'16px', border:'1px solid #e2e8f0', overflow:'hidden', transition:'all .2s', boxShadow:'0 2px 8px rgba(0,0,0,0.05)' },
  cardOpen: { boxShadow:'0 12px 32px rgba(0,0,0,0.1)', borderColor:'#cbd5e1', transform:'translateY(-2px)' },
  cardHead: { display:'flex', alignItems:'flex-start', gap:'12px', padding:'16px', background:'none', border:'none', width:'100%', cursor:'pointer', fontFamily:'inherit', textAlign:'left' },
  cardQ: { fontSize:'14px', fontWeight:'700', color:NAVY, lineHeight:'1.45', flex:1, letterSpacing:'-0.01em' },
  cardQku: { fontSize:'12px', color:'#64748b', direction:'rtl', textAlign:'right', marginTop:'5px', fontWeight:'500' },
  cardChev: { fontSize:'11px', transition:'transform .2s', flexShrink:0, marginTop:'4px' },
  cardBody: { padding:'0 16px 16px 32px' },
  cardAns: { fontSize:'13.5px', color:'#334155', lineHeight:'1.8', whiteSpace:'pre-line' },
  cardKurd: { marginTop:'0', padding:'12px 14px', background:'#fff7ed', borderLeft:'3px solid', borderRadius:'8px' },
  cardKurdLabel: { fontSize:'10px', fontWeight:'800', textTransform:'uppercase', letterSpacing:'0.1em', marginBottom:'8px' },
  noKu: { marginTop:'12px', padding:'8px 12px', background:'#f8fafc', borderRadius:'8px', fontSize:'12px', color:'#94a3b8', fontStyle:'italic' },
  cardFoot: { display:'flex', gap:'6px', marginTop:'14px', flexWrap:'wrap' },
  catTag: { fontSize:'10px', fontWeight:'700', padding:'3px 10px', borderRadius:'6px' },
  subTag: { background:'#f1f5f9', color:'#64748b', fontSize:'10px', fontWeight:'600', padding:'3px 10px', borderRadius:'6px' },

  empty: { textAlign:'center', padding:'70px 40px', background:'#fff', borderRadius:'20px', border:'1px solid #e2e8f0', boxShadow:'0 2px 8px rgba(0,0,0,0.04)' },
  emptyTitle: { fontSize:'20px', fontWeight:'800', color:NAVY, marginBottom:'8px', letterSpacing:'-0.02em' },
  emptySub: { fontSize:'14px', color:'#94a3b8' },
};